import os, anthropic
from langsmith import traceable, Client

# These environment variables activate LangSmith tracing automatically.
# os.environ["LANGCHAIN_TRACING_V2"] = "true"
# os.environ["LANGCHAIN_API_KEY"] = "ls__..."
# os.environ["LANGCHAIN_PROJECT"] = "my-agent"

@traceable(name="llm_call", run_type="llm")
def call_model(messages: list, model: str = "claude-haiku-4-5-20251001") -> dict:
    client = anthropic.Anthropic()
    resp = client.messages.create(model=model, max_tokens=256, messages=messages)
    return {
        "output": " ".join(b.text for b in resp.content if hasattr(b, "text")),
        "input_tokens": resp.usage.input_tokens,
        "output_tokens": resp.usage.output_tokens,
    }

@traceable(name="tool_call", run_type="tool")
def run_calculator(expression: str) -> str:
    try:
        return str(eval(expression, {"__builtins__": {}}))
    except Exception as e:
        return f"Error: {e}"

@traceable(name="agent_run", run_type="chain")
def run_agent(task: str) -> str:
    messages = [{"role": "user", "content": task}]
    for _ in range(6):
        result = call_model(messages)
        text = result["output"]
        # Simplified: if the model mentions a calculation, use the calculator
        if "calculate" in text.lower() or any(op in text for op in ["+", "-", "*", "/"]):
            calc_result = run_calculator("56 * 78")  # placeholder
            messages.append({"role": "assistant", "content": text})
            messages.append({"role": "user", "content": f"Tool result: {calc_result}"})
        else:
            return text
    return "Max steps reached"

answer = run_agent("What is 56 times 78?")
print(f"Answer: {answer}")
