import anthropic, json, time

def color(code: int, text: str) -> str:
    """ANSI colour helper for terminal output."""
    return f"\033[{code}m{text}\033[0m"

class DebugConsole:
    def __init__(self, enabled: bool = True):
        self.enabled = enabled
        self._t0 = time.monotonic()

    def _elapsed(self) -> str:
        return f"+{(time.monotonic() - self._t0)*1000:.0f}ms"

    def on_llm_start(self, messages: list) -> None:
        if not self.enabled: return
        last = messages[-1]["content"] if messages else ""
        print(color(34, f"  [{self._elapsed()}] → LLM  | last_msg: {str(last)[:80]}"))

    def on_llm_end(self, text: str, stop_reason: str, tokens: tuple) -> None:
        if not self.enabled: return
        inp, out = tokens
        print(color(32, f"  [{self._elapsed()}] ← LLM  | stop={stop_reason} tok={inp}+{out} | {text[:80]}"))

    def on_tool_call(self, name: str, args: dict) -> None:
        if not self.enabled: return
        print(color(33, f"  [{self._elapsed()}] → TOOL {name} | args={json.dumps(args)[:60]}"))

    def on_tool_result(self, name: str, result: str) -> None:
        if not self.enabled: return
        print(color(35, f"  [{self._elapsed()}] ← TOOL {name} | {result[:80]}"))

    def on_end(self, final: str) -> None:
        if not self.enabled: return
        print(color(36, f"  [{self._elapsed()}] DONE  | {final[:100]}"))

def run_with_debug(task: str, debug: bool = True) -> str:
    client = anthropic.Anthropic()
    console = DebugConsole(enabled=debug)
    messages = [{"role": "user", "content": task}]

    tools = [
        {
            "name": "calculator",
            "description": "Evaluate a mathematical expression.",
            "input_schema": {
                "type": "object",
                "properties": {"expression": {"type": "string"}},
                "required": ["expression"],
            },
        }
    ]

    print(color(1, f"Agent task: {task}"))
    final = ""
    for _ in range(8):
        console.on_llm_start(messages)
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=256,
            tools=tools,
            messages=messages,
        )
        text = " ".join(b.text for b in resp.content if hasattr(b, "text"))
        console.on_llm_end(text, resp.stop_reason,
                           (resp.usage.input_tokens, resp.usage.output_tokens))

        if resp.stop_reason == "end_turn":
            final = text
            break

        if resp.stop_reason == "tool_use":
            tool_results = []
            for block in resp.content:
                if block.type == "tool_use":
                    console.on_tool_call(block.name, block.input)
                    try:
                        result = str(eval(block.input.get("expression", "0"),
                                          {"__builtins__": {}}))
                    except Exception as e:
                        result = str(e)
                    console.on_tool_result(block.name, result)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages += [
                {"role": "assistant", "content": resp.content},
                {"role": "user", "content": tool_results},
            ]

    console.on_end(final)
    return final

run_with_debug("What is (9 * 9) + (4 * 4)?")

import json, pathlib, dataclasses
from typing import Iterator

# Simulate reading a JSONL trajectory store
TRAJECTORY_DIR = pathlib.Path("logs/trajectories")

@dataclasses.dataclass
class EvalExample:
    task: str
    final_answer: str
    status: str
    steps: int
    label: str | None = None      # "good" | "bad" | None (unlabelled)

def load_runs(directory: pathlib.Path) -> Iterator[dict]:
    for path in directory.glob("*.jsonl"):
        events = [json.loads(line) for line in path.read_text().splitlines() if line]
        run_start = next((e for e in events if e["event"] == "run_start"), None)
        run_end   = next((e for e in events if e["event"] == "run_end"),   None)
        if run_start and run_end:
            yield {
                "task":         run_start.get("task", ""),
                "final_answer": run_end.get("final_answer", ""),
                "status":       run_end.get("status", "unknown"),
                "steps":        run_end.get("steps", 0),
            }

def curate_dataset(
    directory: pathlib.Path,
    max_steps_threshold: int = 5,
) -> tuple[list[EvalExample], list[EvalExample]]:
    """
    Heuristically label runs as good or bad.
    Returns (good_examples, bad_examples).
    """
    good, bad = [], []
    for run in load_runs(directory):
        ex = EvalExample(**run)
        if run["status"] == "success" and run["steps"] <= max_steps_threshold:
            ex.label = "good"
            good.append(ex)
        elif run["status"] == "error" or run["steps"] > max_steps_threshold:
            ex.label = "bad"
            bad.append(ex)
    return good, bad

def export_dataset(examples: list[EvalExample], output_path: str) -> None:
    with open(output_path, "w") as f:
        for ex in examples:
            f.write(json.dumps(dataclasses.asdict(ex)) + "\n")
    print(f"Exported {len(examples)} examples to {output_path}")

# Only run if we have a logs directory
import os
if os.path.exists("logs/trajectories"):
    good, bad = curate_dataset(TRAJECTORY_DIR)
    if good or bad:
        export_dataset(good + bad, "/tmp/eval_dataset.jsonl")
    else:
        print("No runs found — run the agent first to populate logs/trajectories/")
else:
    print("No logs directory — create logs/trajectories/ and run the agent first")
